import React, { useState, useEffect, useRef } from 'react';
import API from '../api/axios';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [isFocused, setIsFocused] = useState(false);
    const [activeTab, setActiveTab] = useState('login');
    const navigate = useNavigate();
    const canvasRef = useRef(null);

    // Particle system for background
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;

        const ctx = canvas.getContext('2d');
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;

        const particles = [];
        const particleCount = 150;
        const ticketSymbols = ["🎫", "📋", "✅", "🔄", "🔧", "📊", "👤", "🔒", "🚀", "📈"];

        class Particle {
            constructor() {
                this.x = Math.random() * canvas.width;
                this.y = Math.random() * canvas.height;
                this.size = Math.random() * 20 + 8;
                this.speedX = Math.random() * 1 - 0.5;
                this.speedY = Math.random() * 1 - 0.5;
                this.color = `hsl(${Math.random() * 60 + 180}, 100%, ${Math.random() * 30 + 60}%)`;
                this.symbol = ticketSymbols[Math.floor(Math.random() * ticketSymbols.length)];
                this.rotation = Math.random() * 360;
                this.rotationSpeed = Math.random() * 2 - 1;
                this.alpha = Math.random() * 0.5 + 0.2;
                this.wobble = Math.random() * 0.05;
                this.wobbleSpeed = Math.random() * 0.03;
                this.wobbleOffset = Math.random() * Math.PI * 2;
            }

            update() {
                this.x += this.speedX;
                this.y += this.speedY;
                this.rotation += this.rotationSpeed;

                // Boundary check
                if (this.x > canvas.width) this.x = 0;
                if (this.x < 0) this.x = canvas.width;
                if (this.y > canvas.height) this.y = 0;
                if (this.y < 0) this.y = canvas.height;

                // Wobble effect
                this.size += Math.sin(Date.now() * this.wobbleSpeed + this.wobbleOffset) * this.wobble;
            }

            draw() {
                ctx.save();
                ctx.globalAlpha = this.alpha;
                ctx.translate(this.x, this.y);
                ctx.rotate(this.rotation * Math.PI / 180);

                // Draw ticket-like shape with gradient
                const gradient = ctx.createRadialGradient(0, 0, 0, 0, 0, this.size);
                gradient.addColorStop(0, this.color);
                gradient.addColorStop(1, 'transparent');

                // Draw background circle
                ctx.fillStyle = gradient;
                ctx.beginPath();
                ctx.arc(0, 0, this.size, 0, Math.PI * 2);
                ctx.fill();

                // Draw ticket symbol
                ctx.fillStyle = 'white';
                ctx.font = `${this.size * 0.8}px Arial`;
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                ctx.fillText(this.symbol, 0, 0);

                ctx.restore();
            }
        }

        // Initialize particles
        for (let i = 0; i < particleCount; i++) {
            particles.push(new Particle());
        }

        let animationFrameId;

        const animate = () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Draw subtle grid
            ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)';
            ctx.lineWidth = 1;
            const gridSize = 50;

            for (let x = 0; x < canvas.width; x += gridSize) {
                ctx.beginPath();
                ctx.moveTo(x, 0);
                ctx.lineTo(x, canvas.height);
                ctx.stroke();
            }

            for (let y = 0; y < canvas.height; y += gridSize) {
                ctx.beginPath();
                ctx.moveTo(0, y);
                ctx.lineTo(canvas.width, y);
                ctx.stroke();
            }

            // Draw connecting lines between close particles
            particles.forEach((p1, i) => {
                particles.slice(i + 1).forEach(p2 => {
                    const dx = p1.x - p2.x;
                    const dy = p1.y - p2.y;
                    const distance = Math.sqrt(dx * dx + dy * dy);

                    if (distance < 100) {
                        ctx.beginPath();
                        ctx.strokeStyle = `rgba(100, 200, 255, ${0.2 * (1 - distance/100)})`;
                        ctx.lineWidth = 1;
                        ctx.moveTo(p1.x, p1.y);
                        ctx.lineTo(p2.x, p2.y);
                        ctx.stroke();
                    }
                });
            });

            // Update and draw particles
            particles.forEach(particle => {
                particle.update();
                particle.draw();
            });

            animationFrameId = requestAnimationFrame(animate);
        };

        animate();

        const handleResize = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        };

        window.addEventListener('resize', handleResize);

        return () => {
            window.removeEventListener('resize', handleResize);
            cancelAnimationFrame(animationFrameId);
        };
    }, []);

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const { data } = await API.post('/auth/login', { email, password });
            localStorage.setItem('token', data.token);
            localStorage.setItem('role', data.role);

            // Add success animation before navigation
            const loginBtn = document.querySelector('.login-btn');
            if (loginBtn) {
                loginBtn.style.background = 'linear-gradient(to right, #00d26a, #00b894)';
                loginBtn.textContent = 'Access Granted!';

                setTimeout(() => {
                    navigate('/dashboard');
                }, 800);
            }
        } catch (err) {
            // Shake animation on error
            const loginForm = document.querySelector('.login-form');
            loginForm.classList.add('shake');
            setTimeout(() => loginForm.classList.remove('shake'), 500);

            // Show error message
            const errorEl = document.querySelector('.error-message');
            if (errorEl) {
                errorEl.textContent = err.response?.data?.message || "Invalid credentials";
                errorEl.style.opacity = '1';

                setTimeout(() => {
                    errorEl.style.opacity = '0';
                }, 3000);
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="login-page">
            {/* Embedded CSS with advanced animations */}
            <style>{`
                @import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&family=Orbitron:wght@400;700&display=swap');

                * {
                    margin: 0;
                    padding: 0;
                    box-sizing: border-box;
                }

                .login-page {
                    height: 100vh;
                    display: flex;
                    justify-content: center;
                    align-items: center;
                    background: linear-gradient(135deg, #0a0e17 0%, #13182a 50%, #1a1f36 100%);
                    overflow: hidden;
                    position: relative;
                    font-family: 'Poppins', sans-serif;
                }

                #bg-canvas {
                    position: absolute;
                    top: 0;
                    left: 0;
                    width: 100%;
                    height: 100%;
                    z-index: 1;
                }

                /* Animated gradient orb */
                .orb {
                    position: absolute;
                    width: 800px;
                    height: 800px;
                    border-radius: 50%;
                    background: radial-gradient(circle, rgba(0, 200, 255, 0.15) 0%, rgba(0, 100, 255, 0.05) 40%, transparent 70%);
                    top: -400px;
                    right: -200px;
                    z-index: 1;
                    animation: orb-float 20s infinite ease-in-out;
                    filter: blur(40px);
                }

                .orb-2 {
                    width: 600px;
                    height: 600px;
                    background: radial-gradient(circle, rgba(150, 0, 255, 0.1) 0%, rgba(100, 0, 200, 0.05) 40%, transparent 70%);
                    bottom: -300px;
                    left: -200px;
                    top: auto;
                    right: auto;
                    animation-delay: -10s;
                }

                @keyframes orb-float {
                    0%, 100% { transform: translate(0, 0) scale(1); }
                    33% { transform: translate(30px, -30px) scale(1.05); }
                    66% { transform: translate(-20px, 20px) scale(0.95); }
                }

                /* Glowing border effect */
                .glow-border {
                    position: absolute;
                    top: -2px;
                    left: -2px;
                    right: -2px;
                    bottom: -2px;
                    background: linear-gradient(45deg, #00d4ff, #0088ff, #0066ff, #0099ff, #00d4ff);
                    border-radius: 24px;
                    z-index: -1;
                    filter: blur(15px);
                    opacity: 0.7;
                    animation: glow-rotate 8s linear infinite;
                }

                @keyframes glow-rotate {
                    0% { transform: rotate(0deg); }
                    100% { transform: rotate(360deg); }
                }

                /* Main login card */
                .login-container {
                    z-index: 10;
                    width: 100%;
                    max-width: 480px;
                    position: relative;
                    padding: 20px;
                }

                .login-card {
                    background: rgba(10, 15, 30, 0.7);
                    backdrop-filter: blur(20px);
                    border: 1px solid rgba(255, 255, 255, 0.1);
                    border-radius: 22px;
                    padding: 50px 40px;
                    box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.8),
                                inset 0 1px 0 rgba(255, 255, 255, 0.1);
                    position: relative;
                    overflow: hidden;
                }

                /* Animated header */
                .login-header {
                    text-align: center;
                    margin-bottom: 40px;
                    position: relative;
                }

                .system-title {
                    font-family: 'Orbitron', sans-serif;
                    font-size: 3.2rem;
                    font-weight: 700;
                    background: linear-gradient(to right, #00d4ff, #0088ff, #0066ff);
                    -webkit-background-clip: text;
                    -webkit-text-fill-color: transparent;
                    background-clip: text;
                    margin-bottom: 8px;
                    letter-spacing: 1px;
                    position: relative;
                    display: inline-block;
                }

                .system-title::after {
                    content: '';
                    position: absolute;
                    width: 100%;
                    height: 4px;
                    background: linear-gradient(to right, transparent, #00d4ff, transparent);
                    bottom: -8px;
                    left: 0;
                    border-radius: 2px;
                }

                .system-subtitle {
                    color: #94a3b8;
                    font-size: 1.1rem;
                    letter-spacing: 3px;
                    text-transform: uppercase;
                    margin-top: 15px;
                    position: relative;
                    display: inline-block;
                }

                .system-subtitle::before, .system-subtitle::after {
                    content: '✦';
                    position: absolute;
                    color: #00d4ff;
                    top: 50%;
                    transform: translateY(-50%);
                }

                .system-subtitle::before { left: -30px; }
                .system-subtitle::after { right: -30px; }

                /* Tab switcher */
                .tab-switcher {
                    display: flex;
                    background: rgba(0, 20, 40, 0.5);
                    border-radius: 12px;
                    padding: 5px;
                    margin-bottom: 30px;
                    border: 1px solid rgba(255, 255, 255, 0.05);
                }

                .tab {
                    flex: 1;
                    text-align: center;
                    padding: 12px;
                    color: #94a3b8;
                    cursor: pointer;
                    border-radius: 8px;
                    font-weight: 500;
                    transition: all 0.3s ease;
                    position: relative;
                    overflow: hidden;
                }

                .tab.active {
                    color: white;
                    background: rgba(0, 150, 255, 0.2);
                    box-shadow: 0 5px 15px rgba(0, 100, 255, 0.2);
                }

                .tab.active::before {
                    content: '';
                    position: absolute;
                    top: 0;
                    left: 0;
                    right: 0;
                    height: 2px;
                    background: linear-gradient(to right, #00d4ff, #0088ff);
                }

                /* Form styles */
                .login-form {
                    position: relative;
                }

                @keyframes shake {
                    0%, 100% { transform: translateX(0); }
                    10%, 30%, 50%, 70%, 90% { transform: translateX(-5px); }
                    20%, 40%, 60%, 80% { transform: translateX(5px); }
                }

                .shake {
                    animation: shake 0.5s cubic-bezier(.36,.07,.19,.97) both;
                }

                .input-group {
                    margin-bottom: 25px;
                    position: relative;
                }

                .input-label {
                    display: block;
                    color: #cbd5e1;
                    margin-bottom: 10px;
                    font-size: 0.9rem;
                    font-weight: 500;
                    display: flex;
                    align-items: center;
                }

                .input-label i {
                    margin-right: 8px;
                    color: #00d4ff;
                }

                .input-field {
                    width: 100%;
                    padding: 18px 20px;
                    background: rgba(5, 15, 30, 0.7);
                    border: 1px solid rgba(255, 255, 255, 0.1);
                    border-radius: 12px;
                    color: white;
                    font-size: 1rem;
                    transition: all 0.3s ease;
                    font-family: 'Poppins', sans-serif;
                }

                .input-field:focus {
                    outline: none;
                    border-color: #00d4ff;
                    box-shadow: 0 0 0 3px rgba(0, 212, 255, 0.2),
                                inset 0 0 10px rgba(0, 212, 255, 0.1);
                    background: rgba(5, 20, 40, 0.8);
                }

                .input-highlight {
                    position: absolute;
                    bottom: 0;
                    left: 0;
                    height: 2px;
                    width: 0;
                    background: linear-gradient(to right, #00d4ff, #0088ff);
                    transition: width 0.4s ease;
                    border-radius: 2px;
                }

                .input-field:focus ~ .input-highlight {
                    width: 100%;
                }

                /* Error message */
                .error-message {
                    color: #ff6b6b;
                    text-align: center;
                    margin: 15px 0;
                    font-size: 0.9rem;
                    opacity: 0;
                    transition: opacity 0.3s ease;
                    min-height: 20px;
                }

                /* Login button */
                .login-btn {
                    width: 100%;
                    padding: 18px;
                    background: linear-gradient(to right, #0066ff, #0099ff, #00d4ff);
                    border: none;
                    border-radius: 12px;
                    color: white;
                    font-size: 1.1rem;
                    font-weight: 600;
                    cursor: pointer;
                    transition: all 0.3s ease;
                    margin-top: 10px;
                    font-family: 'Poppins', sans-serif;
                    letter-spacing: 0.5px;
                    position: relative;
                    overflow: hidden;
                    z-index: 1;
                }

                .login-btn::before {
                    content: '';
                    position: absolute;
                    top: 0;
                    left: -100%;
                    width: 100%;
                    height: 100%;
                    background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.2), transparent);
                    transition: left 0.7s ease;
                    z-index: -1;
                }

                .login-btn:hover {
                    transform: translateY(-3px);
                    box-shadow: 0 10px 25px rgba(0, 100, 255, 0.4);
                }

                .login-btn:hover::before {
                    left: 100%;
                }

                .login-btn:active {
                    transform: translateY(-1px);
                }

                .login-btn:disabled {
                    opacity: 0.6;
                    cursor: not-allowed;
                    transform: none;
                    box-shadow: none;
                }

                /* Footer text */
                .login-footer {
                    text-align: center;
                    margin-top: 30px;
                    color: #64748b;
                    font-size: 0.8rem;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                }

                .secure-indicator {
                    display: inline-flex;
                    align-items: center;
                    background: rgba(0, 200, 100, 0.1);
                    padding: 6px 12px;
                    border-radius: 20px;
                    border: 1px solid rgba(0, 200, 100, 0.3);
                }

                .secure-indicator i {
                    color: #00d26a;
                    margin-right: 6px;
                    font-size: 0.9rem;
                }

                /* Responsive adjustments */
                @media (max-width: 768px) {
                    .login-card {
                        padding: 40px 25px;
                        margin: 0 15px;
                    }

                    .system-title {
                        font-size: 2.5rem;
                    }

                    .orb {
                        width: 500px;
                        height: 500px;
                        top: -250px;
                        right: -150px;
                    }
                }

                @media (max-width: 480px) {
                    .system-title {
                        font-size: 2rem;
                    }

                    .system-subtitle {
                        font-size: 0.9rem;
                        letter-spacing: 2px;
                    }

                    .input-field {
                        padding: 16px;
                    }

                    .login-btn {
                        padding: 16px;
                    }
                }
            `}</style>

            {/* Background Canvas */}
            <canvas id="bg-canvas" ref={canvasRef}></canvas>

            {/* Animated gradient orbs */}
            <div className="orb"></div>
            <div className="orb orb-2"></div>

            {/* Main Login Container */}
            <div className="login-container">
                <div className="glow-border"></div>

                <div className="login-card">
                    {/* Header */}
                    <div className="login-header">
                        <h1 className="system-title">TICKETFLOW</h1>
                        <div className="system-subtitle">Management System</div>
                    </div>

                    {/* Tab Switcher */}
                    <div className="tab-switcher">
                        <div 
                            className={`tab ${activeTab === 'login' ? 'active' : ''}`}
                            onClick={() => setActiveTab('login')}
                        >
                            <i className="fas fa-sign-in-alt"></i> Agent Login
                        </div>
                        <div 
                            className={`tab ${activeTab === 'admin' ? 'active' : ''}`}
                            onClick={() => setActiveTab('admin')}
                        >
                            <i className="fas fa-user-shield"></i> Admin Portal
                        </div>
                    </div>

                    {/* Login Form */}
                    <form className="login-form" onSubmit={handleLogin}>
                        <div className="input-group">
                            <label className="input-label">
                                <i className="fas fa-envelope"></i> Support Agent Email
                            </label>
                            <input 
                                type="email" 
                                className="input-field"
                                placeholder="agent@company.com" 
                                value={email}
                                onChange={e => setEmail(e.target.value)} 
                                onFocus={() => setIsFocused(true)}
                                onBlur={() => setIsFocused(false)}
                                required 
                            />
                            <div className="input-highlight"></div>
                        </div>

                        <div className="input-group">
                            <label className="input-label">
                                <i className="fas fa-lock"></i> Secure Access Password
                            </label>
                            <input 
                                type="password" 
                                className="input-field"
                                placeholder="••••••••••••" 
                                value={password}
                                onChange={e => setPassword(e.target.value)}
                                onFocus={() => setIsFocused(true)}
                                onBlur={() => setIsFocused(false)}
                                required 
                            />
                            <div className="input-highlight"></div>
                        </div>

                        {/* Error Message */}
                        <div className="error-message"></div>

                        {/* Submit Button */}
                        <button type="submit" className="login-btn" disabled={loading}>
                            {loading ? (
                                <>
                                    <i className="fas fa-spinner fa-spin"></i> Authenticating...
                                </>
                            ) : (
                                <>
                                    <i className="fas fa-unlock-alt"></i> Access Control Panel
                                </>
                            )}
                        </button>

                        {/* Footer */}
                        <div className="login-footer">
                            <div className="secure-indicator">
                                <i className="fas fa-shield-alt"></i>
                                <span>ENCRYPTED SECURE CONNECTION</span>
                            </div>
                        </div>
                    </form>
                </div>
            </div>

            {/* Add Font Awesome for icons */}
            <link 
                rel="stylesheet" 
                href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css" 
            />
        </div>
    );
};

export default Login;
